B=(0,0);
C=(5,8.7);
D=(5,2.9);
draw(Circle(A,5),linewidth(0.7));
draw(Circle(B,5),linewidth(0.7));
draw(Circle(C,5),linewidth(0.7));
draw(A--B--C--cycle,linewidth(0.7));
draw(C--D--B,linewidth(0.7));
draw(D--A,linewidth(0.7));
label("1",(2.5,0),S);
